// Document validation utilities for verification system
export interface DocumentValidationError {
  field: string;
  message: string;
}

export interface DocumentValidationResult {
  valid: boolean;
  errors: DocumentValidationError[];
}

const ACCEPTED_MIME_TYPES = ['image/jpeg', 'image/jpg', 'image/png', 'application/pdf'];
const MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024; // 10MB
const MAX_FILES = 5;

export function validateDocuments(documents: string[]): DocumentValidationResult {
  const errors: DocumentValidationError[] = [];

  // Check document count
  if (documents.length === 0) {
    errors.push({
      field: 'documents',
      message: 'At least one document is required'
    });
    return { valid: false, errors };
  }

  if (documents.length > MAX_FILES) {
    errors.push({
      field: 'documents',
      message: `Maximum ${MAX_FILES} documents allowed, got ${documents.length}`
    });
    return { valid: false, errors };
  }

  // Validate each document
  documents.forEach((document, index) => {
    const docErrors = validateSingleDocument(document, index);
    errors.push(...docErrors);
  });

  return {
    valid: errors.length === 0,
    errors
  };
}

function validateSingleDocument(document: string, index: number): DocumentValidationError[] {
  const errors: DocumentValidationError[] = [];
  const fieldName = `documents[${index}]`;

  // Check if it's a data URL
  if (!document.startsWith('data:')) {
    errors.push({
      field: fieldName,
      message: 'Document must be a valid data URL'
    });
    return errors;
  }

  try {
    // Parse data URL to get MIME type and size
    const [header, base64Data] = document.split(',');

    if (!header || !base64Data) {
      errors.push({
        field: fieldName,
        message: 'Invalid data URL format'
      });
      return errors;
    }

    // Extract MIME type
    const mimeMatch = header.match(/data:([^;]+)/);
    if (!mimeMatch) {
      errors.push({
        field: fieldName,
        message: 'Could not determine file type'
      });
      return errors;
    }

    const mimeType = mimeMatch[1].toLowerCase();

    // Validate MIME type
    if (!ACCEPTED_MIME_TYPES.includes(mimeType)) {
      errors.push({
        field: fieldName,
        message: `File type '${mimeType}' not allowed. Allowed types: ${ACCEPTED_MIME_TYPES.join(', ')}`
      });
    }

    // Validate file size (base64 is ~33% larger than original)
    const approximateSize = (base64Data.length * 3) / 4;
    if (approximateSize > MAX_FILE_SIZE_BYTES) {
      const sizeMB = Math.round(approximateSize / (1024 * 1024) * 100) / 100;
      const maxSizeMB = MAX_FILE_SIZE_BYTES / (1024 * 1024);
      errors.push({
        field: fieldName,
        message: `File size ${sizeMB}MB exceeds maximum allowed size of ${maxSizeMB}MB`
      });
    }

    // Additional base64 validation
    if (!/^[A-Za-z0-9+/]*={0,2}$/.test(base64Data)) {
      errors.push({
        field: fieldName,
        message: 'Invalid base64 encoding'
      });
    }

  } catch (error) {
    errors.push({
      field: fieldName,
      message: 'Failed to validate document format'
    });
  }

  return errors;
}

// Rate limiting utilities (simple in-memory store)
const submissionAttempts = new Map<string, number[]>();

export function checkRateLimit(restaurantId: string): { allowed: boolean; nextAllowedTime?: Date } {
  const now = Date.now();
  const oneHour = 60 * 60 * 1000;

  // Get existing attempts for this restaurant
  const attempts = submissionAttempts.get(restaurantId) || [];

  // Remove attempts older than 1 hour
  const recentAttempts = attempts.filter(timestamp => now - timestamp < oneHour);

  // Update the map with cleaned attempts
  submissionAttempts.set(restaurantId, recentAttempts);

  // Check if rate limit exceeded
  if (recentAttempts.length >= 1) { // Max 1 request per hour
    const oldestAttempt = Math.min(...recentAttempts);
    const nextAllowedTime = new Date(oldestAttempt + oneHour);

    return {
      allowed: false,
      nextAllowedTime
    };
  }

  // Record this attempt
  recentAttempts.push(now);
  submissionAttempts.set(restaurantId, recentAttempts);

  return { allowed: true };
}

// Clean up old rate limit entries periodically
setInterval(() => {
  const now = Date.now();
  const oneHour = 60 * 60 * 1000;

  for (const [restaurantId, attempts] of Array.from(submissionAttempts.entries())) {
    const recentAttempts = attempts.filter((timestamp: number) => now - timestamp < oneHour);
    if (recentAttempts.length === 0) {
      submissionAttempts.delete(restaurantId);
    } else {
      submissionAttempts.set(restaurantId, recentAttempts);
    }
  }
}, 15 * 60 * 1000); // Clean up every 15 minutes

client/src/pages/restaurant-detail.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { useParams, Link } from "wouter";
import Navigation from "@/components/navigation";
import DealCard from "@/components/deal-card";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { BackHeader } from "@/components/back-header";
import { MapPin, Phone, Star, Clock, Navigation as DirectionsIcon, Heart, CheckCircle, Store } from "lucide-react";
import { SEOHead } from "@/components/seo-head";

export default function RestaurantDetailPage() {
  const { id: restaurantId } = useParams();

  const { data: restaurant, isLoading: restaurantLoading } = useQuery({
    queryKey: ["/api/restaurants", restaurantId],
    enabled: !!restaurantId,
  });

  const { data: reviews } = useQuery({
    queryKey: ["/api/reviews/restaurant", restaurantId],
    enabled: !!restaurantId,
  });

  const { data: rating } = useQuery({
    queryKey: ["/api/reviews/restaurant", restaurantId, "rating"],
    enabled: !!restaurantId,
  });

  const { data: featuredDeals } = useQuery({
    queryKey: ["/api/deals/featured"],
    enabled: true,
  });

  if (restaurantLoading) {
    return (
      <div className="max-w-md mx-auto bg-background min-h-screen relative pb-20">
        <div className="animate-pulse">
          <div className="w-full h-64 bg-muted"></div>
          <div className="p-6 space-y-4">
            <div className="h-8 bg-muted rounded w-3/4"></div>
            <div className="h-4 bg-muted rounded w-1/2"></div>
            <div className="h-20 bg-muted rounded"></div>
          </div>
        </div>
      </div>
    );
  }

  if (!restaurant) {
    return (
      <div className="max-w-md mx-auto bg-background min-h-screen relative pb-20">
        <div className="text-center py-12">
          <h2 className="text-xl font-bold mb-4">Restaurant not found</h2>
          <Link href="/">
            <Button>Back to Home</Button>
          </Link>
        </div>
        <Navigation />
      </div>
    );
  }

  // Filter deals for this restaurant
  const allDeals = Array.isArray(featuredDeals) ? featuredDeals : [];
  const restaurantDeals = allDeals.filter((deal: any) => deal.restaurantId === restaurantId);

  const currentRating = (rating as any)?.rating || 0;
  const reviewCount = Array.isArray(reviews) ? reviews.length : 0;

  const rightActions = (
    <Button variant="ghost" size="sm" className="bg-white/90 backdrop-blur-sm" data-testid="button-save-restaurant">
      <Heart className="w-4 h-4" />
    </Button>
  );

  const restaurantName = (restaurant as any)?.name || 'Restaurant';
  const cuisineType = (restaurant as any)?.cuisineType || 'food';
  const address = (restaurant as any)?.address || '';
  const description = `Visit ${restaurantName} and discover exclusive food deals. ${cuisineType} restaurant with ${restaurantDeals.length} active deals. ${currentRating > 0 ? `Rated ${currentRating.toFixed(1)} stars by ${reviewCount} customers.` : ''}`;

  const localBusinessSchema = {
    "@context": "https://schema.org",
    "@type": "Restaurant",
    "name": restaurantName,
    "description": description,
    "address": {
      "@type": "PostalAddress",
      "streetAddress": address
    },
    "telephone": (restaurant as any)?.phone || "",
    "servesCuisine": cuisineType,
    "url": `https://mealscout.replit.app/restaurants/${restaurantId}`,
    ...(currentRating > 0 && reviewCount > 0 ? {
      "aggregateRating": {
        "@type": "AggregateRating",
        "ratingValue": currentRating.toFixed(1),
        "reviewCount": reviewCount
      }
    } : {})
  };

  return (
    <div className="max-w-md mx-auto bg-background min-h-screen relative pb-20">
      <SEOHead
        title={`${restaurantName} - ${cuisineType} Restaurant | MealScout`}
        description={description}
        keywords={`${restaurantName}, ${cuisineType} restaurant, restaurant deals, ${address}, food discounts`}
        canonicalUrl={`https://mealscout.replit.app/restaurants/${restaurantId}`}
        schemaData={localBusinessSchema}
      />
      <BackHeader
        title={restaurantName}
        fallbackHref="/"
        icon={Store}
        rightActions={rightActions}
      />

      {/* Header Image */}
      <div className="relative h-48 bg-gradient-to-br from-red-100 to-orange-100 overflow-hidden">
        <div className="absolute inset-0 bg-black/20"></div>

        {/* Restaurant Image Placeholder */}
        <div className="w-full h-full flex items-center justify-center">
          <div className="text-center text-white/80">
            <div className="w-20 h-20 bg-white/20 rounded-2xl flex items-center justify-center mx-auto mb-4">
              <span className="text-2xl">🍽️</span>
            </div>
          </div>
        </div>
      </div>

      {/* Restaurant Info */}
      <div className="px-6 py-6">
        <div className="mb-6">
          <div className="flex items-start justify-between mb-2">
            <h1 className="text-2xl font-bold text-foreground flex items-center space-x-2" data-testid="text-restaurant-name">
              <span>{(restaurant as any)?.name}</span>
              {(restaurant as any)?.isVerified && (
                <CheckCircle className="w-5 h-5 text-green-500" data-testid="icon-verified-restaurant" />
              )}
            </h1>
            {(restaurant as any)?.cuisineType && (
              <Badge variant="secondary" data-testid="badge-cuisine-type">
                {(restaurant as any)?.cuisineType}
              </Badge>
            )}
          </div>

          {/* Rating */}
          <div className="flex items-center space-x-4 mb-4">
            <div className="flex items-center space-x-1">
              <Star className="w-4 h-4 fill-yellow-400 text-yellow-400" />
              <span className="font-semibold" data-testid="text-rating">
                {currentRating.toFixed(1)}
              </span>
              <span className="text-muted-foreground text-sm" data-testid="text-review-count">
                ({reviewCount} reviews)
              </span>
            </div>
            <div className="flex items-center space-x-1 text-sm text-green-600">
              <Clock className="w-4 h-4" />
              <span>Open now</span>
            </div>
          </div>

          {/* Address */}
          <div className="flex items-start space-x-2 mb-4">
            <MapPin className="w-4 h-4 text-muted-foreground mt-0.5" />
            <div>
              <p className="text-sm text-foreground" data-testid="text-restaurant-address">
                {(restaurant as any)?.address}
              </p>
            </div>
          </div>

          {/* Contact Info */}
          {(restaurant as any)?.phone && (
            <div className="flex items-center space-x-2 mb-6">
              <Phone className="w-4 h-4 text-muted-foreground" />
              <p className="text-sm text-foreground" data-testid="text-restaurant-phone">
                {(restaurant as any)?.phone}
              </p>
            </div>
          )}

          {/* Action Buttons */}
          <div className="flex space-x-3">
            <Button className="flex-1" data-testid="button-directions">
              <DirectionsIcon className="w-4 h-4 mr-2" />
              Directions
            </Button>
            <Button variant="outline" className="flex-1" data-testid="button-call-restaurant">
              <Phone className="w-4 h-4 mr-2" />
              Call
            </Button>
          </div>
        </div>

        {/* Current Deals */}
        <div className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Current Deals</h2>
          {restaurantDeals.length > 0 ? (
            <div className="space-y-4">
              {restaurantDeals.map((deal: any) => (
                <DealCard key={deal.id} deal={deal} />
              ))}
            </div>
          ) : (
            <Card>
              <CardContent className="p-6 text-center">
                <div className="w-16 h-16 bg-muted rounded-2xl flex items-center justify-center mx-auto mb-4">
                  <span className="text-2xl">🎯</span>
                </div>
                <p className="text-muted-foreground">No current deals available</p>
                <p className="text-sm text-muted-foreground mt-1">Check back soon!</p>
              </CardContent>
            </Card>
          )}
        </div>

        {/* Reviews */}
        <div>
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-xl font-bold text-foreground">Reviews</h2>
            <Button variant="outline" size="sm" data-testid="button-write-review">
              Write Review
            </Button>
          </div>

          {Array.isArray(reviews) && reviews.length > 0 ? (
            <div className="space-y-4">
              {reviews.slice(0, 3).map((review: any) => (
                <Card key={review.id}>
                  <CardContent className="p-4">
                    <div className="flex items-start space-x-3">
                      <div className="w-8 h-8 bg-primary/10 rounded-full flex items-center justify-center">
                        <span className="text-sm font-medium">U</span>
                      </div>
                      <div className="flex-1">
                        <div className="flex items-center space-x-2 mb-1">
                          <span className="font-medium text-sm">User</span>
                          <div className="flex">
                            {[1, 2, 3, 4, 5].map((star) => (
                              <Star 
                                key={star} 
                                className={`w-3 h-3 ${star <= (review.rating || 0) ? 'fill-yellow-400 text-yellow-400' : 'text-gray-300'}`} 
                              />
                            ))}
                          </div>
                        </div>
                        <p className="text-sm text-muted-foreground">{review.comment}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          ) : (
            <Card>
              <CardContent className="p-6 text-center">
                <div className="w-16 h-16 bg-muted rounded-2xl flex items-center justify-center mx-auto mb-4">
                  <Star className="w-6 h-6 text-muted-foreground" />
                </div>
                <p className="text-muted-foreground">No reviews yet</p>
                <p className="text-sm text-muted-foreground mt-1">Be the first to review this restaurant!</p>
              </CardContent>
            </Card>
          )}
        </div>
      </div>

      <Navigation />
    </div>
  );
}

client/src/components/deal-feedback.tsx.content:
import { useState } from 'react';
import { Star } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { useToast } from '@/hooks/use-toast';
import { useMutation, useQuery } from '@tanstack/react-query';
import { apiRequest, queryClient } from '@/lib/queryClient';

interface DealFeedbackProps {
  dealId: string;
  compact?: boolean;
}

export function DealFeedback({ dealId, compact = false }: DealFeedbackProps) {
  const { toast } = useToast();
  const [rating, setRating] = useState(0);
  const [hoveredRating, setHoveredRating] = useState(0);
  const [feedbackType, setFeedbackType] = useState<'rating' | 'suggestion' | 'issue'>('rating');
  const [comment, setComment] = useState('');
  const [isHelpful, setIsHelpful] = useState<boolean | null>(null);
  const [showForm, setShowForm] = useState(false);

  const { data: stats } = useQuery<{
    averageRating: number;
    totalFeedback: number;
    ratingDistribution: { [key: number]: number };
  }>({
    queryKey: ['/api/deals', dealId, 'feedback', 'stats'],
  });

  const submitFeedbackMutation = useMutation({
    mutationFn: async (data: any) => {
      return await apiRequest('POST', `/api/deals/${dealId}/feedback`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/deals', dealId, 'feedback'] });
      queryClient.invalidateQueries({ queryKey: ['/api/deals', dealId, 'feedback', 'stats'] });

      toast({
        title: "Thank you!",
        description: "Your feedback helps us improve deal quality.",
      });

      setRating(0);
      setComment('');
      setFeedbackType('rating');
      setIsHelpful(null);
      setShowForm(false);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to submit feedback. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleSubmit = () => {
    if (rating === 0) {
      toast({
        title: "Rating Required",
        description: "Please select a star rating before submitting.",
        variant: "destructive",
      });
      return;
    }

    submitFeedbackMutation.mutate({
      rating,
      feedbackType,
      comment: comment.trim() || null,
      isHelpful,
    });
  };

  if (compact) {
    return (
      <div 
        className="flex items-center gap-2" 
        data-testid="feedback-compact"
        onClick={(e) => e.stopPropagation()}
      >
        {stats && stats.totalFeedback > 0 && (
          <div className="flex items-center gap-1 text-sm">
            <Star className="h-4 w-4 fill-yellow-400 text-yellow-400" />
            <span className="font-medium">{stats.averageRating.toFixed(1)}</span>
            <span className="text-muted-foreground">({stats.totalFeedback})</span>
          </div>
        )}
        {!showForm ? (
          <Button
            variant="outline"
            size="sm"
            onClick={(e) => {
              e.stopPropagation();
              setShowForm(true);
            }}
            className="text-sm font-medium"
            data-testid="button-show-feedback-form"
          >
            Rate Deal
          </Button>
        ) : (
          <div className="flex items-center gap-2">
            <div className="flex gap-1">
              {[1, 2, 3, 4, 5].map((star) => (
                <button
                  key={star}
                  onClick={(e) => {
                    e.stopPropagation();
                    setRating(star);
                  }}
                  onMouseEnter={() => setHoveredRating(star)}
                  onMouseLeave={() => setHoveredRating(0)}
                  className="transition-transform hover:scale-110"
                  data-testid={`star-${star}`}
                >
                  <Star
                    className={`h-5 w-5 ${
                      star <= (hoveredRating || rating)
                        ? 'fill-yellow-400 text-yellow-400'
                        : 'text-gray-300'
                    }`}
                  />
                </button>
              ))}
            </div>
            <Button
              size="sm"
              onClick={(e) => {
                e.stopPropagation();
                handleSubmit();
              }}
              disabled={rating === 0 || submitFeedbackMutation.isPending}
              data-testid="button-submit-rating"
            >
              {submitFeedbackMutation.isPending ? 'Submitting...' : 'Submit'}
            </Button>
            <Button
              variant="ghost"
              size="sm"
              onClick={(e) => {
                e.stopPropagation();
                setShowForm(false);
              }}
              data-testid="button-cancel-feedback"
            >
              Cancel
            </Button>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-4 p-4 border rounded-lg" data-testid="feedback-full">
      <div>
        <h3 className="text-lg font-semibold mb-2">Rate This Deal</h3>
        {stats && stats.totalFeedback > 0 && (
          <div className="flex items-center gap-2 mb-4">
            <div className="flex items-center gap-1">
              <Star className="h-5 w-5 fill-yellow-400 text-yellow-400" />
              <span className="font-medium text-lg">{stats.averageRating.toFixed(1)}</span>
            </div>
            <span className="text-sm text-muted-foreground">
              Based on {stats.totalFeedback} {stats.totalFeedback === 1 ? 'review' : 'reviews'}
            </span>
          </div>
        )}
      </div>

      <div>
        <Label className="mb-2 block">Your Rating</Label>
        <div className="flex gap-2">
          {[1, 2, 3, 4, 5].map((star) => (
            <button
              key={star}
              onClick={() => setRating(star)}
              onMouseEnter={() => setHoveredRating(star)}
              onMouseLeave={() => setHoveredRating(0)}
              className="transition-transform hover:scale-110"
              data-testid={`star-${star}`}
            >
              <Star
                className={`h-8 w-8 ${
                  star <= (hoveredRating || rating)
                    ? 'fill-yellow-400 text-yellow-400'
                    : 'text-gray-300'
                }`}
              />
            </button>
          ))}
        </div>
      </div>

      <div>
        <Label className="mb-2 block">Feedback Type</Label>
        <RadioGroup
          value={feedbackType}
          onValueChange={(value: any) => setFeedbackType(value)}
          data-testid="feedback-type-selector"
        >
          <div className="flex items-center space-x-2">
            <RadioGroupItem value="rating" id="rating" data-testid="radio-rating" />
            <Label htmlFor="rating" className="cursor-pointer">General Rating</Label>
          </div>
          <div className="flex items-center space-x-2">
            <RadioGroupItem value="suggestion" id="suggestion" data-testid="radio-suggestion" />
            <Label htmlFor="suggestion" className="cursor-pointer">Suggestion for Improvement</Label>
          </div>
          <div className="flex items-center space-x-2">
            <RadioGroupItem value="issue" id="issue" data-testid="radio-issue" />
            <Label htmlFor="issue" className="cursor-pointer">Report an Issue</Label>
          </div>
        </RadioGroup>
      </div>

      <div>
        <Label className="mb-2 block">Did the deal work as expected?</Label>
        <RadioGroup
          value={isHelpful === null ? '' : isHelpful.toString()}
          onValueChange={(value) => setIsHelpful(value === 'true')}
          data-testid="helpful-selector"
        >
          <div className="flex items-center space-x-2">
            <RadioGroupItem value="true" id="helpful-yes" data-testid="radio-helpful-yes" />
            <Label htmlFor="helpful-yes" className="cursor-pointer">Yes</Label>
          </div>
          <div className="flex items-center space-x-2">
            <RadioGroupItem value="false" id="helpful-no" data-testid="radio-helpful-no" />
            <Label htmlFor="helpful-no" className="cursor-pointer">No</Label>
          </div>
        </RadioGroup>
      </div>

      <div>
        <Label htmlFor="comment" className="mb-2 block">
          Additional Comments (Optional)
        </Label>
        <Textarea
          id="comment"
          placeholder="Share your experience with this deal..."
          value={comment}
          onChange={(e) => setComment(e.target.value)}
          maxLength={500}
          rows={4}
          data-testid="textarea-comment"
        />
        <p className="text-xs text-muted-foreground mt-1">
          {comment.length}/500 characters
        </p>
      </div>

      <div className="flex gap-2">
        <Button
          onClick={handleSubmit}
          disabled={rating === 0 || submitFeedbackMutation.isPending}
          data-testid="button-submit-feedback"
        >
          {submitFeedbackMutation.isPending ? 'Submitting...' : 'Submit Feedback'}
        </Button>
        {rating > 0 && (
          <Button
            variant="outline"
            onClick={() => {
              setRating(0);
              setComment('');
              setFeedbackType('rating');
              setIsHelpful(null);
            }}
            data-testid="button-reset-feedback"
          >
            Reset
          </Button>
        )}
      </div>
    </div>
  );
}

