@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* DoorDash-inspired Color Palette */
  --background: hsl(0 0% 98%);
  --background-gradient: linear-gradient(135deg, hsl(0 0% 99%) 0%, hsl(0 0% 97%) 100%);
  --foreground: hsl(0 0% 9%);

  --card: hsl(0 0% 100%);
  --card-foreground: hsl(0 0% 9%);

  --popover: hsl(0 0% 100%);
  --popover-foreground: hsl(0 0% 9%);

  /* DoorDash red primary */
  --primary: hsl(0 72% 51%);
  --primary-foreground: hsl(0 0% 100%);

  /* Clean gray secondary */
  --secondary: hsl(0 0% 96%);
  --secondary-foreground: hsl(0 0% 9%);

  /* Light gray backgrounds */
  --muted: hsl(0 0% 96%);
  --muted-foreground: hsl(0 0% 45%);

  /* Clean accent */
  --accent: hsl(0 0% 96%);
  --accent-foreground: hsl(0 0% 9%);

  --destructive: hsl(0 84% 60%);
  --destructive-foreground: hsl(0 0% 100%);

  --border: hsl(0 0% 90%);
  --input: hsl(0 0% 96%);
  --ring: hsl(0 72% 51%);

  --radius: 12px;
}

.dark {
  --background: hsl(0 0% 4%);
  --foreground: hsl(0 0% 96%);

  --card: hsl(0 0% 8%);
  --card-foreground: hsl(0 0% 95%);

  --popover: hsl(0 0% 6%);
  --popover-foreground: hsl(0 0% 96%);

  --primary: hsl(0 72% 51%);
  --primary-foreground: hsl(0 0% 100%);

  --secondary: hsl(0 0% 14%);
  --secondary-foreground: hsl(0 0% 100%);

  --muted: hsl(0 0% 11%);
  --muted-foreground: hsl(0 0% 54%);

  --accent: hsl(0 0% 14%);
  --accent-foreground: hsl(0 0% 100%);

  --destructive: hsl(0 72% 51%);
  --destructive-foreground: hsl(0 0% 100%);

  --border: hsl(0 0% 18%);
  --input: hsl(0 0% 18%);
  --ring: hsl(0 72% 51%);
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    background: var(--background-gradient);
    @apply text-foreground;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
    min-height: 100vh;
  }

  /* Modern app background */
  .app-background {
    background: linear-gradient(
      135deg, 
      hsl(0 0% 99%) 0%, 
      hsl(0 0% 97%) 50%, 
      hsl(0 0% 95%) 100%
    );
    min-height: 100vh;
  }

  /* Animated gradient background */
  .animated-gradient-bg {
    background: linear-gradient(
      -45deg, 
      hsl(0 72% 51%), 
      hsl(14 88% 55%), 
      hsl(28 76% 47%), 
      hsl(45 93% 58%),
      hsl(0 72% 51%)
    );
    background-size: 400% 400%;
    animation: gradientShift 15s ease infinite;
    min-height: 100vh;
    position: relative;
  }

  .animated-gradient-bg::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(
      135deg,
      rgba(255, 255, 255, 0.1) 0%,
      rgba(255, 255, 255, 0.05) 50%,
      rgba(0, 0, 0, 0.05) 100%
    );
    pointer-events: none;
  }

  @keyframes gradientShift {
    0% {
      background-position: 0% 50%;
    }
    50% {
      background-position: 100% 50%;
    }
    100% {
      background-position: 0% 50%;
    }
  }

  /* Clean typography */
  h1, h2, h3, h4, h5, h6 {
    font-weight: 600;
    line-height: 1.2;
  }

  /* Clean button styles */
  button {
    font-weight: 500;
  }

  /* Clean input styles */
  input, textarea {
    font-size: 16px;
  }

  /* Custom scrollbar */
  ::-webkit-scrollbar {
    width: 6px;
    height: 6px;
  }

  ::-webkit-scrollbar-track {
    background: transparent;
  }

  ::-webkit-scrollbar-thumb {
    background: hsl(0 0% 80%);
    border-radius: 3px;
  }

  ::-webkit-scrollbar-thumb:hover {
    background: hsl(0 0% 70%);
  }
}

@layer utilities {
  /* Clean shadows */
  .shadow-clean {
    box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.1), 0 1px 2px 0 rgba(0, 0, 0, 0.06);
  }

  .shadow-clean-lg {
    box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
  }

  /* DoorDash-style card hover */
  .card-hover {
    transition: box-shadow 0.2s ease-in-out;
  }

  .card-hover:hover {
    box-shadow: 0 4px 12px 0 rgba(0, 0, 0, 0.15);
  }

  /* Glass morphism effects */
  .glass-card {
    background: rgba(255, 255, 255, 0.1);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.2);
  }

  /* Floating animation for background elements */
  .floating-element {
    animation: float 6s ease-in-out infinite;
  }

  @keyframes float {
    0% {
      transform: translateY(0px) rotate(0deg);
    }
    33% {
      transform: translateY(-20px) rotate(1deg);
    }
    66% {
      transform: translateY(-10px) rotate(-1deg);
    }
    100% {
      transform: translateY(0px) rotate(0deg);
    }
  }

  /* Responsive improvements */
  @media (min-width: 768px) {
    .mobile-only {
      display: none;
    }
  }

  @media (max-width: 767px) {
    .desktop-only {
      display: none;
    }
  }
}

