import { useState, useEffect } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { Link, useParams } from "wouter";
import { useAuth } from "@/hooks/useAuth";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { isUnauthorizedError } from "@/lib/authUtils";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import DealClaimModal from "@/components/deal-claim-modal";
import DealShareModal from "@/components/deal-share-modal";
import { BackHeader } from "@/components/back-header";
import { Tag, ArrowLeft } from "lucide-react";
import { SEOHead } from "@/components/seo-head";

interface Deal {
  id: string;
  restaurantId: string;
  title: string;
  description: string;
  dealType: string;
  discountValue: string;
  minOrderAmount?: string;
  imageUrl?: string;
  startDate: string;
  endDate: string;
  startTime: string;
  endTime: string;
  perCustomerLimit: number;
  currentUses: number;
}

interface Restaurant {
  id: string;
  name: string;
  address: string;
  phone?: string;
  cuisineType?: string;
}

export default function DealDetail() {
  const { id: dealId } = useParams();
  const { user, isAuthenticated } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [showClaimModal, setShowClaimModal] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);

  const { data: deal, isLoading: dealLoading } = useQuery({
    queryKey: ["/api/deals", dealId],
    enabled: !!dealId,
  });

  const { data: restaurant, isLoading: restaurantLoading } = useQuery({
    queryKey: ["/api/restaurants", (deal as Deal)?.restaurantId],
    enabled: !!(deal as Deal)?.restaurantId,
  });

  const { data: reviews } = useQuery({
    queryKey: ["/api/reviews/restaurant", (deal as Deal)?.restaurantId],
    enabled: !!(deal as Deal)?.restaurantId,
  });

  const { data: rating } = useQuery({
    queryKey: ["/api/reviews/restaurant", (deal as Deal)?.restaurantId, "rating"],
    enabled: !!(deal as Deal)?.restaurantId,
  });

  // Track deal view when deal is loaded
  useEffect(() => {
    if (dealId && deal && !dealLoading) {
      // Track the deal view
      const trackView = async () => {
        try {
          await apiRequest('POST', `/api/deals/${dealId}/view`, {});
        } catch (error) {
          // Silently fail - view tracking shouldn't interrupt user experience
          console.debug('View tracking failed:', error);
        }
      };

      // Delay to ensure the user actually viewed the page (not just a quick navigation)
      const timer = setTimeout(trackView, 1000);
      return () => clearTimeout(timer);
    }
  }, [dealId, deal, dealLoading]);

  const claimDealMutation = useMutation({
    mutationFn: async () => {
      return await apiRequest("POST", `/api/deals/${dealId}/claim`, {});
    },
    onSuccess: () => {
      toast({
        title: "Deal Claimed!",
        description: "You have successfully claimed this deal. Show this to the restaurant.",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/deals", dealId] });
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/auth/google/customer";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: error.message || "Failed to claim deal",
        variant: "destructive",
      });
    },
  });

  if (dealLoading || restaurantLoading) {
    return (
      <div className="max-w-md lg:max-w-4xl xl:max-w-6xl mx-auto bg-white min-h-screen">
        <div className="animate-pulse">
          <div className="w-full h-64 bg-muted"></div>
          <div className="p-4 space-y-4">
            <div className="h-6 bg-muted rounded w-3/4"></div>
            <div className="h-4 bg-muted rounded w-1/2"></div>
            <div className="h-20 bg-muted rounded"></div>
          </div>
        </div>
      </div>
    );
  }

  if (!deal) {
    return (
      <div className="max-w-md lg:max-w-4xl xl:max-w-6xl mx-auto bg-white min-h-screen flex items-center justify-center">
        <Card>
          <CardContent className="p-6 text-center">
            <i className="fas fa-exclamation-triangle text-muted-foreground text-3xl mb-4"></i>
            <p className="text-muted-foreground mb-4">Deal not found</p>
            <Link href="/">
              <Button>Back to Home</Button>
            </Link>
          </CardContent>
        </Card>
      </div>
    );
  }

  const formatDiscount = (deal: Deal) => {
    if (deal.dealType === "percentage") {
      return `${deal.discountValue}% OFF`;
    } else {
      return `$${deal.discountValue} OFF`;
    }
  };

  const formatTime = (timeString: string) => {
    const [hours, minutes] = timeString.split(':');
    const hour = parseInt(hours);
    const ampm = hour >= 12 ? 'PM' : 'AM';
    const displayHour = hour % 12 || 12;
    return `${displayHour}:${minutes} ${ampm}`;
  };

  const dealTitle = (deal as Deal)?.title || 'Food Deal';
  const restaurantName = (restaurant as Restaurant)?.name || 'Restaurant';
  const dealDescription = (deal as Deal)?.description || 'Exclusive food deal from a local restaurant';
  const discountValue = (deal as Deal)?.discountValue || '';
  const dealType = (deal as Deal)?.dealType || '';

  const offerSchema = {
    "@context": "https://schema.org",
    "@type": "Offer",
    "name": dealTitle,
    "description": dealDescription,
    "url": `https://mealscout.replit.app/deals/${dealId}`,
    "priceCurrency": "USD",
    "price": dealType === 'percentage' ? '0' : discountValue,
    "discount": dealType === 'percentage' ? `${discountValue}%` : `$${discountValue}`,
    "seller": {
      "@type": "Restaurant",
      "name": restaurantName,
      "address": (restaurant as Restaurant)?.address || ""
    },
    "validFrom": (deal as Deal)?.startDate,
    "validThrough": (deal as Deal)?.endDate,
    "availability": "https://schema.org/InStock"
  };

  return (
    <div className="max-w-md lg:max-w-4xl xl:max-w-6xl mx-auto bg-white min-h-screen">
      <SEOHead
        title={`${dealTitle} - ${restaurantName} | MealScout`}
        description={`${dealDescription}. ${dealType === 'percentage' ? `Get ${discountValue}% off` : `Save $${discountValue}`} at ${restaurantName}. Claim this exclusive deal now on MealScout!`}
        keywords={`${restaurantName}, ${dealTitle}, food deal, restaurant discount, ${(restaurant as Restaurant)?.cuisineType || 'food'}`}
        canonicalUrl={`https://mealscout.replit.app/deals/${dealId}`}
        schemaData={offerSchema}
      />
      <BackHeader
        title="Deal Details"
        fallbackHref="/"
        icon={Tag}
        className="bg-white sticky top-0 z-10"
      />

      {/* Action Buttons */}
      <div className="bg-white px-4 py-2 border-b border-border sticky top-16 z-10">
        <div className="flex justify-end space-x-2">
          <button 
            className="p-2 rounded-full hover:bg-muted" 
            onClick={() => setShowShareModal(true)}
            data-testid="button-share"
          >
            <i className="fas fa-share text-foreground"></i>
          </button>
          <button className="p-2 rounded-full hover:bg-muted" data-testid="button-favorite">
            <i className="fas fa-heart text-muted-foreground hover:text-primary"></i>
          </button>
        </div>
      </div>

      {/* Deal Image */}
      <div className="relative">
        <div className="w-full h-64 bg-gradient-to-r from-primary/20 to-secondary/20 flex items-center justify-center">
          {(deal as Deal)?.imageUrl ? (
            <img 
              src={(deal as Deal).imageUrl} 
              alt={(deal as Deal).title} 
              className="w-full h-full object-cover"
              data-testid="img-deal"
            />
          ) : (
            <i className="fas fa-utensils text-primary text-4xl"></i>
          )}
        </div>
        <div className="absolute top-4 left-4 bg-accent text-accent-foreground px-3 py-1 rounded-full font-bold text-sm" data-testid="text-discount-badge">
          {formatDiscount(deal as Deal)}
        </div>
      </div>

      {/* Deal Content */}
      <div className="px-4 py-6 pb-32">
        {/* Restaurant Info */}
        <div className="flex items-start justify-between mb-4">
          <div>
            <h1 className="text-xl font-bold text-foreground mb-1" data-testid="text-restaurant-name">
              {(restaurant as Restaurant)?.name || "Restaurant"}
            </h1>
            <div className="flex items-center space-x-4 text-sm text-muted-foreground">
              <div className="flex items-center space-x-1">
                <i className="fas fa-map-marker-alt"></i>
                <span data-testid="text-restaurant-distance">0.2 mi away</span>
              </div>
              <div className="flex items-center space-x-1">
                <i className="fas fa-star text-yellow-400"></i>
                <span data-testid="text-restaurant-rating">
                  {(rating as any)?.rating && typeof (rating as any).rating === 'number' ? (rating as any).rating.toFixed(1) : 
                   (rating as any)?.rating && !isNaN(Number((rating as any).rating)) ? Number((rating as any).rating).toFixed(1) : "New"} 
                  {Array.isArray(reviews) && ` (${reviews.length} reviews)`}
                </span>
              </div>
            </div>
          </div>
          <div className="w-16 h-16 bg-primary rounded-full flex items-center justify-center">
            <i className="fas fa-utensils text-white text-xl"></i>
          </div>
        </div>

        {/* Deal Description */}
        <Card className="bg-muted/50 mb-6">
          <CardContent className="p-4">
            <h2 className="font-semibold text-foreground mb-2" data-testid="text-deal-title">{(deal as Deal)?.title}</h2>
            <p className="text-muted-foreground text-sm mb-3" data-testid="text-deal-description">{(deal as Deal)?.description}</p>

            <div className="flex items-center space-x-4 text-xs">
              <div className="flex items-center space-x-1">
                <i className="fas fa-clock text-muted-foreground"></i>
                <span data-testid="text-deal-time">
                  Valid {formatTime((deal as Deal)?.startTime || "11:00")} - {formatTime((deal as Deal)?.endTime || "15:00")}
                </span>
              </div>
              {(deal as Deal)?.minOrderAmount && (
                <div className="flex items-center space-x-1">
                  <i className="fas fa-dollar-sign text-muted-foreground"></i>
                  <span data-testid="text-min-order">Min. order ${(deal as Deal).minOrderAmount}</span>
                </div>
              )}
            </div>
          </CardContent>
        </Card>

        {/* Quick Actions */}
        <div className="grid grid-cols-3 gap-3 mb-6">
          <Card>
            <CardContent className="text-center p-3">
              <i className="fas fa-clock text-secondary text-lg mb-1"></i>
              <p className="text-xs font-medium text-foreground" data-testid="text-pickup-time">15-25 min</p>
              <p className="text-xs text-muted-foreground">Pickup time</p>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="text-center p-3">
              <i className="fas fa-phone text-primary text-lg mb-1"></i>
              <p className="text-xs font-medium text-foreground">Call Now</p>
              <p className="text-xs text-muted-foreground" data-testid="text-restaurant-phone">
                {(restaurant as Restaurant)?.phone || "(555) 123-4567"}
              </p>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="text-center p-3">
              <i className="fas fa-directions text-accent text-lg mb-1"></i>
              <p className="text-xs font-medium text-foreground">Directions</p>
              <p className="text-xs text-muted-foreground" data-testid="text-directions">2 blocks away</p>
            </CardContent>
          </Card>
        </div>

        {/* Reviews */}
        {Array.isArray(reviews) && reviews.length > 0 && (
          <div className="mb-6">
            <div className="flex items-center justify-between mb-3">
              <h3 className="font-semibold text-foreground" data-testid="text-reviews-title">Recent Reviews</h3>
              <button className="text-primary text-sm font-medium" data-testid="button-see-all-reviews">See all</button>
            </div>

            <div className="space-y-4">
              {(reviews as any[]).slice(0, 2).map((review: any, index: number) => (
                <Card key={review.id}>
                  <CardContent className="p-4">
                    <div className="flex items-center space-x-3 mb-2">
                      <div className="w-8 h-8 rounded-full bg-muted flex items-center justify-center">
                        <i className="fas fa-user text-muted-foreground text-xs"></i>
                      </div>
                      <div className="flex-1">
                        <div className="flex items-center space-x-2">
                          <p className="font-medium text-sm text-foreground" data-testid={`text-reviewer-name-${index}`}>
                            {review.user?.firstName || "Anonymous"}
                          </p>
                          <div className="flex text-yellow-400">
                            {[...Array(5)].map((_, i) => (
                              <i 
                                key={i} 
                                className={`fas fa-star text-xs ${i < review.rating ? 'text-yellow-400' : 'text-muted-foreground'}`}
                              ></i>
                            ))}
                          </div>
                        </div>
                        <p className="text-xs text-muted-foreground" data-testid={`text-review-date-${index}`}>
                          {new Date(review.createdAt).toLocaleDateString()}
                        </p>
                      </div>
                    </div>
                    <p className="text-sm text-foreground" data-testid={`text-review-comment-${index}`}>
                      {review.comment || "Great deal!"}
                    </p>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Bottom Action Bar */}
      <div className="fixed bottom-0 left-1/2 transform -translate-x-1/2 w-full max-w-md bg-white border-t border-border px-4 py-4">
        <div className="flex items-center space-x-3">
          <Button 
            className="flex-1 py-3 font-semibold text-sm food-gradient-primary border-0"
            onClick={() => setShowClaimModal(true)}
            disabled={!isAuthenticated}
            data-testid="button-claim-deal"
          >
            <i className="fab fa-facebook-f mr-2"></i>
            Claim & Post to Facebook
          </Button>
          <Button 
            variant="outline" 
            size="icon" 
            className="px-4 py-3"
            data-testid="button-save-deal"
          >
            <i className="fas fa-heart text-muted-foreground"></i>
          </Button>
        </div>
        <p className="text-center text-xs text-muted-foreground mt-2" data-testid="text-deal-expires">
          Deal expires in {Math.ceil((new Date((deal as Deal)?.endDate || Date.now()).getTime() - Date.now()) / (1000 * 60 * 60 * 24))} days
        </p>
      </div>

      {/* Deal Claim Modal */}
      <DealClaimModal
        dealId={dealId || ''}
        isOpen={showClaimModal}
        onClose={() => setShowClaimModal(false)}
      />

      {/* Deal Share Modal */}
      <DealShareModal
        isOpen={showShareModal}
        onClose={() => setShowShareModal(false)}
        deal={{
          id: (deal as Deal)?.id || '',
          title: (deal as Deal)?.title || '',
          description: (deal as Deal)?.description || '',
          discountValue: (deal as Deal)?.discountValue || '0',
          minOrderAmount: (deal as Deal)?.minOrderAmount,
          restaurant: {
            name: (restaurant as Restaurant)?.name || 'Restaurant',
            cuisineType: (restaurant as Restaurant)?.cuisineType,
          }
        }}
      />
    </div>
  );
}

server/storage.ts.content:
import {
  users,
  restaurants,
  deals,
  dealClaims,
  reviews,
  verificationRequests,
  dealViews,
  foodTruckSessions,
  foodTruckLocations,
  restaurantFavorites,
  restaurantRecommendations,
  userAddresses,
  passwordResetTokens,
  dealFeedback,
  type User,
  type UpsertUser,
  type Restaurant,
  type InsertRestaurant,
  type Deal,
  type InsertDeal,
  type DealClaim,
  type InsertDealClaim,
  type Review,
  type InsertReview,
  type VerificationRequest,
  type InsertVerificationRequest,
  type DealView,
  type InsertDealView,
  type FoodTruckSession,
  type InsertFoodTruckSession,
  type FoodTruckLocation,
  type InsertFoodTruckLocation,
  type UpdateRestaurantMobileSettings,
  type RestaurantFavorite,
  type InsertRestaurantFavorite,
  type RestaurantRecommendation,
  type InsertRestaurantRecommendation,
  type UserAddress,
  type InsertUserAddress,
  type PasswordResetToken,
  type InsertPasswordResetToken,
  type DealFeedback,
  type InsertDealFeedback,
  type GoogleUserData,
  type EmailUserData,
  type FacebookUserData,
  type UpdateRestaurantLocation,
  type OperatingHours,
} from "@shared/schema";
import { db } from "./db";
import { eq, and, or, gte, lte, sql, desc, asc, inArray, isNull, isNotNull, not } from "drizzle-orm";
import bcrypt from "bcryptjs";

// Interface for storage operations
export interface IStorage {
  // User operations
  // (IMPORTANT) these user operations are mandatory for authentication.
  getUser(id: string): Promise<User | undefined>;
  getUserByEmail(email: string): Promise<User | undefined>;
  upsertUser(user: UpsertUser): Promise<User>;
  upsertUserByAuth(authType: 'google' | 'email' | 'facebook', userData: GoogleUserData | EmailUserData | FacebookUserData, userType?: 'customer' | 'restaurant_owner'): Promise<User>;
  updateUserStripeInfo(id: string, stripeCustomerId: string, stripeSubscriptionId: string, subscriptionBillingInterval?: string): Promise<User>;
  updateUser(id: string, updates: Partial<Pick<User, 'subscriptionBillingInterval' | 'stripeCustomerId' | 'stripeSubscriptionId'>>): Promise<User>;

  // Restaurant operations
  createRestaurant(restaurant: InsertRestaurant): Promise<Restaurant>;
  getRestaurant(id: string): Promise<Restaurant | undefined>;
  getRestaurantsByOwner(ownerId: string): Promise<Restaurant[]>;
  updateRestaurant(id: string, restaurant: Partial<InsertRestaurant>): Promise<Restaurant>;
  getNearbyRestaurants(lat: number, lng: number, radiusKm: number): Promise<Restaurant[]>;
  getSubscribedRestaurants(lat: number, lng: number, radiusKm: number): Promise<Restaurant[]>;
  verifyRestaurantOwnership(restaurantId: string, userId: string): Promise<boolean>;

  // Deal operations
  createDeal(deal: InsertDeal): Promise<Deal>;
  getDeal(id: string): Promise<Deal | undefined>;
  getDealsByRestaurant(restaurantId: string): Promise<Deal[]>;
  getActiveDeals(): Promise<Deal[]>;
  getFilteredDeals(showLimitedTimeOnly?: boolean): Promise<Deal[]>;
  getNearbyDeals(lat: number, lng: number, radiusKm: number): Promise<Deal[]>;
  searchDeals(filters: {
    query?: string;
    cuisineType?: string;
    minPrice?: number;
    maxPrice?: number;
    latitude?: number;
    longitude?: number;
    radius?: number;
    sortBy?: string;
  }): Promise<Deal[]>;
  updateDeal(id: string, deal: Partial<InsertDeal>): Promise<Deal>;
  incrementDealUses(id: string): Promise<void>;
  deactivateUserDeals(userId: string): Promise<void>;
  deleteDeal(id: string): Promise<void>;
  duplicateDeal(id: string): Promise<Deal>;

  // Deal claim operations
  claimDeal(claim: InsertDealClaim): Promise<DealClaim>;
  getUserDealClaims(userId: string): Promise<DealClaim[]>;
  getDealClaimsCount(dealId: string, userId?: string): Promise<number>;
  getRestaurantDealClaims(restaurantId: string, status?: string): Promise<any[]>;
  verifyRestaurantOwnershipByClaim(claimId: string, userId: string): Promise<boolean>;

  // Review operations
  createReview(review: InsertReview): Promise<Review>;
  getRestaurantReviews(restaurantId: string): Promise<Review[]>;
  getRestaurantAverageRating(restaurantId: string): Promise<number>;

  // Admin operations
  ensureAdminExists(): Promise<void>;

  // Verification operations
  createVerificationRequest(verificationRequest: InsertVerificationRequest): Promise<VerificationRequest>;
  getVerificationRequestsByOwner(ownerId: string): Promise<VerificationRequest[]>;
  getVerificationRequests(): Promise<(VerificationRequest & { restaurant: { id: string; name: string; address: string; ownerId: string } })[]>;
  approveVerificationRequest(id: string, reviewerId: string): Promise<void>;
  rejectVerificationRequest(id: string, reviewerId: string, reason: string): Promise<void>;
  setRestaurantVerified(restaurantId: string, isVerified: boolean): Promise<void>;
  hasPendingVerificationRequest(restaurantId: string): Promise<boolean>;

  // Deal view tracking operations
  recordDealView(view: InsertDealView): Promise<DealView>;
  getDealViewsCount(dealId: string, dateRange?: { start: Date; end: Date }): Promise<number>;
  hasRecentDealView(dealId: string, userId?: string, sessionId?: string, timeWindowMs?: number): Promise<boolean>;

  // Deal claim revenue operations
  markClaimAsUsed(claimId: string, orderAmount: number): Promise<DealClaim>;

  // Advanced analytics operations
  getRestaurantAnalyticsSummary(restaurantId: string, dateRange?: { start: Date; end: Date }): Promise<{
    totalViews: number;
    totalClaims: number;
    totalRevenue: number;
    conversionRate: number;
    topDeals: Array<{ dealId: string; title: string; views: number; claims: number; revenue: number }>;
  }>;

  getRestaurantAnalyticsTimeseries(restaurantId: string, dateRange: { start: Date; end: Date }, interval: 'day' | 'week'): Promise<Array<{
    date: string;
    views: number;
    claims: number;
    revenue: number;
  }>>;

  getRestaurantCustomerInsights(restaurantId: string, dateRange?: { start: Date; end: Date }): Promise<{
    repeatCustomers: number;
    averageOrderValue: number;
    peakHours: Array<{ hour: number; count: number }>;
    demographics: {
      ageGroups: Array<{ range: string; count: number }>;
      genderBreakdown: Array<{ gender: string; count: number }>;
    };
  }>;

  getRestaurantAnalyticsExport(restaurantId: string, dateRange: { start: Date; end: Date }): Promise<Array<{
    dealTitle: string;
    date: string;
    views: number;
    claims: number;
    revenue: number;
  }>>;

  // Food truck operations
  setRestaurantMobileSettings(restaurantId: string, settings: UpdateRestaurantMobileSettings): Promise<Restaurant>;
  updateRestaurantLocation(restaurantId: string, location: UpdateRestaurantLocation): Promise<Restaurant>;
  setRestaurantOperatingHours(restaurantId: string, operatingHours: OperatingHours): Promise<Restaurant>;
  isRestaurantOpenNow(restaurantId: string): Promise<boolean>;
  startTruckSession(restaurantId: string, deviceId: string, userId: string): Promise<FoodTruckSession>;
  endTruckSession(restaurantId: string, userId: string): Promise<void>;
  getActiveTruckSession(restaurantId: string): Promise<FoodTruckSession | undefined>;
  upsertLiveLocation(location: InsertFoodTruckLocation): Promise<FoodTruckLocation>;
