    const { id: _, createdAt: __, updatedAt: ___, currentUses: ____, ...dealData } = originalDeal;

    const [clonedDeal] = await db
      .insert(deals)
      .values({
        ...dealData,
        title: `${dealData.title} (Copy)`,
        currentUses: 0,
        isActive: false, // Start cloned deals as inactive
