import type { Express } from "express";
import { createServer, type Server } from "http";
import Stripe from "stripe";
import { storage } from "./storage";
import { setupUnifiedAuth, isAuthenticated, isRestaurantOwner } from "./unifiedAuth";
import { emailService } from "./emailService";
import { insertRestaurantSchema, insertDealSchema, insertReviewSchema, insertVerificationRequestSchema, insertDealViewSchema, insertFoodTruckLocationSchema, updateRestaurantMobileSettingsSchema, insertFoodTruckSessionSchema, insertRestaurantFavoriteSchema, insertRestaurantRecommendationSchema, insertUserAddressSchema, insertPasswordResetTokenSchema, updateRestaurantLocationSchema, updateRestaurantOperatingHoursSchema, insertDealFeedbackSchema, type User, deals } from "@shared/schema";
import { z } from "zod";
import { validateDocuments, checkRateLimit } from "./documentValidation";
import { randomBytes, timingSafeEqual, createHash } from "crypto";
import bcrypt from "bcryptjs";
import { broadcastLocationUpdate, broadcastStatusUpdate } from "./websocket";
import { db } from "./db";
import { and, inArray, eq, sql } from "drizzle-orm";

// Optional Stripe integration
const stripe = process.env.STRIPE_SECRET_KEY 
  ? new Stripe(process.env.STRIPE_SECRET_KEY)
  : null;

// Beta mode flag - when enabled, all users get free access to all features
// Defaults to true - set BETA_MODE=false to disable
const BETA_MODE = process.env.BETA_MODE !== 'false';

console.log('🎯 BETA_MODE is', BETA_MODE ? 'ENABLED ✅' : 'DISABLED ❌');
console.log('🎯 process.env.BETA_MODE =', process.env.BETA_MODE);

// Production safety check: warn if beta mode is enabled in production
if (process.env.NODE_ENV === 'production' && BETA_MODE) {
  console.warn('⚠️  WARNING: BETA_MODE is enabled in production environment! All users will have free access to premium features.');
}

// Password reset rate limiting (similar to document submission rate limiting)
const passwordResetAttempts = new Map<string, number[]>();

function checkPasswordResetRateLimit(key: string): { allowed: boolean; nextAllowedTime?: Date; remainingAttempts?: number } {
  const now = Date.now();
  const fifteenMinutes = 15 * 60 * 1000; // 15 minutes
  const maxAttempts = 3; // Max 3 attempts per 15 minutes per IP/email combo

  // Get existing attempts for this key (IP+email combination)
  const attempts = passwordResetAttempts.get(key) || [];

  // Remove attempts older than 15 minutes
  const recentAttempts = attempts.filter(timestamp => now - timestamp < fifteenMinutes);

  // Update the map with cleaned attempts
  passwordResetAttempts.set(key, recentAttempts);

  // Check if rate limit exceeded
  if (recentAttempts.length >= maxAttempts) {
    const oldestAttempt = Math.min(...recentAttempts);
    const nextAllowedTime = new Date(oldestAttempt + fifteenMinutes);

    return {
      allowed: false,
      nextAllowedTime,
      remainingAttempts: 0
    };
  }

  // Record this attempt
  recentAttempts.push(now);
  passwordResetAttempts.set(key, recentAttempts);

  return { 
    allowed: true, 
    remainingAttempts: maxAttempts - recentAttempts.length 
  };
}

// Clean up old password reset rate limit entries periodically
setInterval(() => {
  const now = Date.now();
  const fifteenMinutes = 15 * 60 * 1000;

  for (const [key, attempts] of Array.from(passwordResetAttempts.entries())) {
    const recentAttempts = attempts.filter((timestamp: number) => now - timestamp < fifteenMinutes);
    if (recentAttempts.length === 0) {
      passwordResetAttempts.delete(key);
    } else {
      passwordResetAttempts.set(key, recentAttempts);
    }
  }
}, 5 * 60 * 1000); // Clean up every 5 minutes

// Environment validation for production - now non-blocking to prevent startup failures
function validateEnvironment() {
  const required = ['DATABASE_URL', 'SESSION_SECRET'];
  const missing = required.filter(env => !process.env[env]);

  if (missing.length > 0) {
    console.error(`❌ Missing required environment variables: ${missing.join(', ')}`);
    console.warn('⚠️  Server will start but some features may not work properly');
    // Don't exit process to allow health checks to pass
    return false;
  }
  return true;
}

// Subscription validation function for analytics access
async function validateAnalyticsAccess(userId: string): Promise<{
  hasAccess: boolean;
  error?: string;
  subscriptionTier?: string;
}> {
  try {
    const user = await storage.getUser(userId);
    if (!user) {
      return { hasAccess: false, error: "User not found" };
    }

    // During beta testing, all users get free access to analytics
    if (BETA_MODE) {
      return { hasAccess: true, subscriptionTier: "beta" };
    }

    // Check if user has beta access (free analytics for beta users)
    if (user.subscriptionBillingInterval && !user.stripeSubscriptionId) {
      // Beta user - allow analytics access
      return { hasAccess: true, subscriptionTier: "beta" };
    }

    // Check if user has active subscription
    if (!stripe || !user.stripeSubscriptionId) {
      return { 
        hasAccess: false, 
        error: "Premium subscription required to access analytics. Please upgrade your plan.",
        subscriptionTier: "free"
      };
    }

    // Verify subscription status with Stripe
    const subscription = await stripe.subscriptions.retrieve(user.stripeSubscriptionId);
    if (!subscription || subscription.status !== 'active') {
      return { 
        hasAccess: false, 
        error: "Your subscription is not active. Please check your payment method and try again.",
        subscriptionTier: "inactive"
      };
    }

    // Return subscription tier for different feature access
    // Handle both new format (standard-month) and legacy formats
    const billingInterval = user.subscriptionBillingInterval || '';
    let tier = 'monthly'; // default

    if (billingInterval.startsWith('standard-')) {
      const interval = billingInterval.replace('standard-', '');
      tier = interval === 'year' ? 'yearly' : interval === 'quarter' ? 'quarterly' : 'monthly';
    } else if (billingInterval === 'multiple-deals' || billingInterval.includes('multiple-deals')) {
      tier = 'multiple-deals';
    } else if (billingInterval === 'single-deal' || billingInterval.includes('single-deal')) {
      tier = 'single-deal';
    } else if (billingInterval === 'year' || billingInterval.includes('year')) {
      tier = 'yearly';
    } else if (billingInterval === '3-month' || billingInterval === 'quarter' || billingInterval.includes('quarter')) {
      tier = 'quarterly';
    }

    return { 
      hasAccess: true, 
      subscriptionTier: tier
    };
  } catch (error) {
    console.error("Analytics access validation error:", error);
    return { 
      hasAccess: false, 
      error: "Unable to verify subscription status. Please try again.",
      subscriptionTier: "error"
    };
  }
}

// Subscription validation function - Now allows unlimited deals for all paid subscriptions
async function validateSubscriptionLimits(userId: string, excludeDealId?: string): Promise<{
  isValid: boolean;
  error?: string;
  currentCount?: number;
  maxDeals?: number;
}> {
  try {
    const user = await storage.getUser(userId);
    if (!user) {
      return { isValid: false, error: "User not found" };
    }

    console.log('🔍 validateSubscriptionLimits - BETA_MODE:', BETA_MODE);
    console.log('🔍 validateSubscriptionLimits - User ID:', userId);

    // During beta testing, all users get unlimited deals
    if (BETA_MODE) {
      console.log('✅ BETA_MODE enabled - granting unlimited deals');
      return { isValid: true, currentCount: 0, maxDeals: 999 };
    }

    // Check if user has beta access (free)
    if (user.subscriptionBillingInterval && !user.stripeSubscriptionId) {
      // Beta user - allow unlimited deals for now
      return { isValid: true, currentCount: 0, maxDeals: 999 };
    }

    // Check if user has active subscription
    if (!stripe) {
      return { 
        isValid: false, 
        error: "Active subscription required to create deals. Please upgrade your plan.",
        currentCount: 0,
        maxDeals: 0
      };
    }

    let subscriptionId = user.stripeSubscriptionId;

    // Fallback: If subscription ID is missing but customer ID exists, check Stripe for active subscriptions
    if (!subscriptionId && user.stripeCustomerId) {
      try {
        const subscriptions = await stripe.subscriptions.list({
          customer: user.stripeCustomerId,
          status: 'active',
          limit: 1,
        });

        if (subscriptions.data.length > 0) {
          const activeSubscription = subscriptions.data[0];
          subscriptionId = activeSubscription.id;

          // Auto-sync the subscription to database for future checks
          const intervalMap: { [key: string]: string } = {
            'month': 'month',
            'year': 'year',
          };
          const interval = activeSubscription.items.data[0]?.price?.recurring?.interval;
          const intervalCount = activeSubscription.items.data[0]?.price?.recurring?.interval_count || 1;

          let billingInterval = 'month';
          if (interval === 'month' && intervalCount === 3) {
            billingInterval = 'quarter';
          } else if (interval === 'year') {
            billingInterval = 'year';
          }

          await storage.updateUserStripeInfo(
            user.id, 
            user.stripeCustomerId, 
            subscriptionId, 
            `standard-${billingInterval}`
          );

          console.log(`✅ Auto-synced subscription ${subscriptionId} for user ${user.id}`);
        }
      } catch (error) {
        console.error('Error checking Stripe for active subscriptions:', error);
      }
    }

    if (!subscriptionId) {
      return { 
        isValid: false, 
        error: "Active subscription required to create deals. Please upgrade your plan.",
        currentCount: 0,
        maxDeals: 0
      };
    }

    // Verify subscription status with Stripe
    const subscription = await stripe.subscriptions.retrieve(subscriptionId);
    if (!subscription || subscription.status !== 'active') {
      return { 
        isValid: false, 
        error: "Your subscription is not active. Please check your payment method and try again.",
        currentCount: 0,
        maxDeals: 0
      };
    }

    // Get user's restaurants and count active deals (for reporting purposes)
    const restaurants = await storage.getRestaurantsByOwner(userId);
    let activeDealsCount = 0;

    for (const restaurant of restaurants) {
      const deals = await storage.getDealsByRestaurant(restaurant.id);
      const activeDeals = deals.filter(d => d.isActive && (!excludeDealId || d.id !== excludeDealId));
      activeDealsCount += activeDeals.length;
    }

    // All paid subscriptions now get unlimited deals
    const maxDeals = 999; // Unlimited deals for all paid plans

    return { 
      isValid: true, 
      currentCount: activeDealsCount, 
      maxDeals 
    };
  } catch (error) {
    console.error("Subscription validation error:", error);
    return { 
      isValid: false, 
      error: "Unable to verify subscription status. Please try again.",
      currentCount: 0,
      maxDeals: 0
    };
  }
}

