        return res.status(400).json({ message: "No active subscription" });
      }

      const subscription = await stripe.subscriptions.update(
        user.stripeSubscriptionId,
        { cancel_at_period_end: true }
      );

      // If keepAdsLive is false, deactivate deals immediately
      if (!keepAdsLive) {
        await storage.deactivateUserDeals(user.id);
      }

      res.json({
        message: keepAdsLive 
          ? "Subscription will be cancelled at the end of the billing period. Your deals remain active until then."
          : "Subscription will be cancelled at the end of the billing period. Your deals have been deactivated.",
        cancelAt: subscription.cancel_at,
        keepAdsLive,
      });
    } catch (error: any) {
      console.error('Cancel subscription error:', error);
      res.status(500).json({ message: error.message });
    }
  });

  // Deal claiming route with Facebook integration
  app.post('/api/deals/:dealId/claim', isAuthenticated, async (req: any, res) => {
    try {
      const dealId = req.params.dealId;
      const userId = req.user.id;

      // Get deal and restaurant info
      const deal = await storage.getDeal(dealId);
      if (!deal) {
        return res.status(404).json({ message: "Deal not found" });
      }

      const restaurant = await storage.getRestaurant(deal.restaurantId);
      if (!restaurant) {
        return res.status(404).json({ message: "Restaurant not found" });
      }

      // Check if user has already claimed this deal
      const existingClaims = await storage.getDealClaimsCount(dealId, userId);
      if (existingClaims >= (deal.perCustomerLimit || 1)) {
        return res.status(400).json({ message: "Deal already claimed by user" });
      }

      // Check if deal is still available
      if (deal.totalUsesLimit && (deal.currentUses || 0) >= deal.totalUsesLimit) {
        return res.status(400).json({ message: "Deal is no longer available" });
      }

      // Create the deal claim
      await storage.claimDeal({
        dealId,
        userId,
      });

      // Increment deal uses
      await storage.incrementDealUses(dealId);

      // Return Facebook post data
      res.json({
        success: true,
        dealTitle: deal.title,
        restaurantName: restaurant.name,
        restaurantAddress: restaurant.address,
        facebookPostData: {
          message: `Just claimed this amazing deal at ${restaurant.name}! 🍽️\n\n${deal.title}\n\nFound this through MealScout - check it out! #MealScout #FoodDeals`,
          place: restaurant.name,
          link: `${req.protocol}://${req.get('host')}/deal/${dealId}`,
          name: deal.title,
          description: `${deal.description} - Available at ${restaurant.name}`,
        }
      });
    } catch (error: any) {
      console.error("Error claiming deal:", error);
      res.status(500).json({ message: "Failed to claim deal" });
    }
  });

  // Get claimed deals for user
  app.get('/api/deals/claimed', isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user.id;
      const claimedDeals = await storage.getUserDealClaims(userId);
      res.json(claimedDeals);
    } catch (error) {
      console.error("Error fetching claimed deals:", error);
      res.status(500).json({ message: "Failed to fetch claimed deals" });
    }
  });

  // Get claims for restaurant owner's deals
  app.get('/api/restaurants/:restaurantId/claims', isAuthenticated, async (req: any, res) => {
    try {
      const { restaurantId } = req.params;
      const { status } = req.query; // pending, used, all

      // Verify user owns this restaurant
      const isAuthorized = await storage.verifyRestaurantOwnership(restaurantId, req.user.id);
      if (!isAuthorized) {
        return res.status(403).json({ message: "Unauthorized: You can only access analytics for restaurants you own" });
      }

      const claims = await storage.getRestaurantDealClaims(restaurantId, status as string);
      res.json(claims);
    } catch (error) {
      console.error("Error fetching restaurant claims:", error);
      res.status(500).json({ message: "Failed to fetch restaurant claims" });
    }
  });

  // Search suggestions endpoint
  app.get("/api/search/suggestions/:query", async (req, res) => {
    try {
      const { query } = req.params;

      if (!query || query.length < 2) {
        return res.json([]);
      }

      const searchTerm = query.toLowerCase();

      // Get all deals and restaurants for suggestions
      const deals = await storage.getAllDeals();
      const restaurants = await storage.getAllRestaurants();

      const suggestions: any[] = [];

      // Restaurant suggestions
      restaurants.forEach((restaurant: any) => {
        if (restaurant.name.toLowerCase().includes(searchTerm)) {
          suggestions.push({
            id: `restaurant-${restaurant.id}`,
            text: restaurant.name,
            type: "restaurant",
            subtitle: `${restaurant.cuisineType} • ${restaurant.address || 'Restaurant'}`,
          });
        }

        // Cuisine type suggestions
        if (restaurant.cuisineType && restaurant.cuisineType.toLowerCase().includes(searchTerm)) {
          const existing = suggestions.find(s => s.text.toLowerCase() === restaurant.cuisineType.toLowerCase());
          if (!existing) {
            suggestions.push({
              id: `cuisine-${restaurant.cuisineType}`,
              text: restaurant.cuisineType,
              type: "cuisine",
              subtitle: "Food category",
            });
          }
        }
      });

      // Deal suggestions
      deals.forEach((deal: any) => {
        if (deal.title.toLowerCase().includes(searchTerm)) {
          suggestions.push({
            id: `deal-${deal.id}`,
            text: deal.title,
            type: "deal",
            subtitle: `${deal.restaurant?.name || 'Restaurant'} • ${deal.discountValue}% off`,
          });
        }
      });

      // Limit to 8 suggestions and sort by relevance
      const limitedSuggestions = suggestions
        .slice(0, 8)
        .sort((a, b) => {
          // Prioritize exact matches
          const aExact = a.text.toLowerCase().startsWith(searchTerm) ? 1 : 0;
          const bExact = b.text.toLowerCase().startsWith(searchTerm) ? 1 : 0;
          return bExact - aExact;
        });

      res.json(limitedSuggestions);
    } catch (error) {
      console.error("Search suggestions error:", error);
      res.status(500).json({ message: "Failed to get search suggestions" });
    }
  });

  // Admin API endpoints
  app.get('/api/auth/admin/verify', isAuthenticated, async (req: any, res) => {
    try {
      const user = req.user;
      if (user.userType === 'admin') {
        res.json(user);
      } else {
        res.status(403).json({ message: "Admin access required" });
      }
    } catch (error) {
      res.status(500).json({ message: "Failed to verify admin" });
    }
  });

  app.get('/api/admin/stats', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const stats = await storage.getAdminStats();
      res.json(stats);
    } catch (error) {
      console.error("Error fetching admin stats:", error);
      res.status(500).json({ message: "Failed to fetch stats" });
    }
  });

  // Admin endpoint to sync subscriptions from Stripe to database
  app.post('/api/admin/subscriptions/sync', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      if (!stripe) {
        return res.status(500).json({ message: "Stripe not configured" });
      }

      const results = {
        synced: 0,
        skipped: 0,
        errors: 0,
        details: [] as any[]
      };

      // Get all users with Stripe customer IDs
      const allUsers = await storage.getAllUsers();
      const usersWithStripe = allUsers.filter(u => u.stripeCustomerId);

      console.log(`[ADMIN SYNC] Found ${usersWithStripe.length} users with Stripe customer IDs`);

      for (const user of usersWithStripe) {
        try {
          // Skip if user already has subscription ID
          if (user.stripeSubscriptionId) {
            results.skipped++;
            continue;
          }

          // Check Stripe for active subscriptions
          const subscriptions = await stripe.subscriptions.list({
            customer: user.stripeCustomerId!,
            status: 'active',
            limit: 1,
          });

          if (subscriptions.data.length > 0) {
            const subscription = subscriptions.data[0];
            const interval = subscription.items.data[0]?.price?.recurring?.interval;
            const intervalCount = subscription.items.data[0]?.price?.recurring?.interval_count || 1;

            let billingInterval = 'month';
            if (interval === 'month' && intervalCount === 3) {
              billingInterval = 'quarter';
            } else if (interval === 'year') {
              billingInterval = 'year';
            }

            await storage.updateUserStripeInfo(
              user.id,
              user.stripeCustomerId!,
              subscription.id,
              `standard-${billingInterval}`
            );

            results.synced++;
            results.details.push({
              userId: user.id,
              email: user.email,
              subscriptionId: subscription.id,
              billingInterval: `standard-${billingInterval}`,
              status: 'synced'
            });

            console.log(`[ADMIN SYNC] ✅ Synced subscription ${subscription.id} for user ${user.email}`);
          } else {
            results.skipped++;
          }
        } catch (error: any) {
          results.errors++;
          results.details.push({
            userId: user.id,
            email: user.email,
            error: error.message,
            status: 'error'
          });
          console.error(`[ADMIN SYNC] ❌ Error syncing user ${user.email}:`, error);
        }
      }

      console.log(`[ADMIN SYNC] Complete: ${results.synced} synced, ${results.skipped} skipped, ${results.errors} errors`);
      res.json(results);
    } catch (error) {
      console.error("Error syncing subscriptions:", error);
      res.status(500).json({ message: "Failed to sync subscriptions" });
    }
  });

  app.get('/api/admin/restaurants/pending', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const restaurants = await storage.getPendingRestaurants();
      res.json(restaurants);
    } catch (error) {
      console.error("Error fetching pending restaurants:", error);
      res.status(500).json({ message: "Failed to fetch pending restaurants" });
    }
  });

  app.post('/api/admin/restaurants/:id/approve', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      await storage.approveRestaurant(req.params.id);
      res.json({ message: "Restaurant approved successfully" });
    } catch (error) {
      console.error("Error approving restaurant:", error);
      res.status(500).json({ message: "Failed to approve restaurant" });
    }
  });

  app.delete('/api/admin/restaurants/:id', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      await storage.deleteRestaurant(req.params.id);
      res.json({ message: "Restaurant deleted successfully" });
    } catch (error) {
      console.error("Error deleting restaurant:", error);
      res.status(500).json({ message: "Failed to delete restaurant" });
    }
  });

  app.get('/api/admin/users', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const users = await storage.getAllUsers();
      res.json(users);
    } catch (error) {
      console.error("Error fetching users:", error);
      res.status(500).json({ message: "Failed to fetch users" });
    }
  });

  app.patch('/api/admin/users/:id/status', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const { isActive } = req.body;
      await storage.updateUserStatus(req.params.id, isActive);
      res.json({ message: "User status updated successfully" });
    } catch (error) {
      console.error("Error updating user status:", error);
      res.status(500).json({ message: "Failed to update user status" });
    }
  });

  app.get('/api/admin/users/:userId/addresses', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const addresses = await storage.getUserAddresses(req.params.userId);
      res.json(addresses);
    } catch (error) {
      console.error("Error fetching user addresses:", error);
      res.status(500).json({ message: "Failed to fetch user addresses" });
    }
  });

  app.get('/api/admin/deals', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const deals = await storage.getAllDealsWithRestaurants();
      res.json(deals);
    } catch (error) {
      console.error("Error fetching deals:", error);
      res.status(500).json({ message: "Failed to fetch deals" });
    }
  });

  app.get('/api/admin/deals/:dealId/stats', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const dealId = req.params.dealId;
      const [viewsCount, claimsCount, feedbackStats] = await Promise.all([
        storage.getDealViewsCount(dealId),
        storage.getDealClaimsCount(dealId),
        storage.getDealFeedbackStats(dealId),
      ]);

      res.json({
        views: viewsCount,
        claims: claimsCount,
        averageRating: feedbackStats.averageRating,
        totalFeedback: feedbackStats.totalFeedback,
        ratingDistribution: feedbackStats.ratingDistribution,
      });
    } catch (error) {
      console.error("Error fetching deal stats:", error);
      res.status(500).json({ message: "Failed to fetch deal statistics" });
    }
  });

  app.delete('/api/admin/deals/:dealId', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      await storage.deleteDeal(req.params.dealId);
      res.json({ message: "Deal deleted successfully" });
    } catch (error) {
      console.error("Error deleting deal:", error);
      res.status(500).json({ message: "Failed to delete deal" });
    }
  });

  app.post('/api/admin/deals/:dealId/clone', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const clonedDeal = await storage.duplicateDeal(req.params.dealId);
      res.json(clonedDeal);
    } catch (error) {
      console.error("Error cloning deal:", error);
      res.status(500).json({ message: "Failed to clone deal" });
    }
  });

  app.patch('/api/admin/deals/:dealId/status', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const { isActive } = req.body;
      await storage.updateDeal(req.params.dealId, { isActive });
      res.json({ message: "Deal status updated successfully" });
    } catch (error) {
      console.error("Error updating deal status:", error);
      res.status(500).json({ message: "Failed to update deal status" });
    }
  });

  app.patch('/api/admin/deals/:dealId/extend', isAuthenticated, async (req: any, res) => {
    try {
      if (req.user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const { days } = req.body;
      if (!days || days < 1) {
        return res.status(400).json({ message: "Invalid number of days" });
      }

      const deal = await storage.getDeal(req.params.dealId);
      if (!deal) {
        return res.status(404).json({ message: "Deal not found" });
      }

      const newEndDate = new Date(deal.endDate);
      newEndDate.setDate(newEndDate.getDate() + days);

      await storage.updateDeal(req.params.dealId, { endDate: newEndDate });
      res.json({ message: `Deal extended by ${days} days`, newEndDate });
    } catch (error) {
      console.error("Error extending deal:", error);
      res.status(500).json({ message: "Failed to extend deal" });
    }
  });


  // Admin verification routes
  app.get('/api/admin/verifications', isAuthenticated, async (req: any, res) => {
    try {
      const user = req.user;
      if (user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const { status } = req.query;
      let verifications = await storage.getVerificationRequests();

      // Filter by status if provided
      if (status && ['pending', 'approved', 'rejected'].includes(status as string)) {
        verifications = verifications.filter(v => v.status === status);
      }

      res.json(verifications);
    } catch (error) {
      console.error("Error fetching verification requests:", error);
      res.status(500).json({ message: "Failed to fetch verification requests" });
    }
  });

  app.post('/api/admin/verifications/:id/approve', isAuthenticated, async (req: any, res) => {
    try {
      const user = req.user;
      if (user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const { id } = req.params;
      await storage.approveVerificationRequest(id, user.id);
      res.json({ success: true, message: "Verification request approved" });
    } catch (error) {
      console.error("Error approving verification request:", error);
      res.status(500).json({ message: "Failed to approve verification request" });
    }
  });

  app.post('/api/admin/verifications/:id/reject', isAuthenticated, async (req: any, res) => {
    try {
      const user = req.user;
      if (user.userType !== 'admin') {
        return res.status(403).json({ message: "Admin access required" });
      }

      const { id } = req.params;
      const { reason } = req.body;

      if (!reason || reason.trim().length === 0) {
        return res.status(400).json({ message: "Rejection reason is required" });
      }

      await storage.rejectVerificationRequest(id, user.id, reason);
      res.json({ success: true, message: "Verification request rejected" });
    } catch (error) {
      console.error("Error rejecting verification request:", error);
      res.status(500).json({ message: "Failed to reject verification request" });
    }
  });

  // Bug report endpoint
  app.post('/api/bug-report', async (req, res) => {
    try {
      const { screenshot, currentUrl, userAgent } = req.body;

      if (!currentUrl || !userAgent) {
        return res.status(400).json({ message: "Missing required bug report data" });
      }

      const user = req.user as User | undefined;
      const userName = user ? `${user.firstName || ''} ${user.lastName || ''}`.trim() : undefined;
      const userEmail = user?.email || undefined;

      const bugReportData = {
        userEmail,
        userName,
        userAgent,
        currentUrl,
        timestamp: new Date().toLocaleString(),
        screenshotUrl: screenshot || undefined,
      };

      const success = await emailService.sendBugReport(bugReportData);

      if (success) {
        res.json({ success: true, message: "Bug report sent successfully" });
      } else {
        res.status(500).json({ message: "Failed to send bug report. Email service may not be configured." });
      }
    } catch (error) {
      console.error("Error submitting bug report:", error);
      res.status(500).json({ message: "Failed to submit bug report" });
    }
  });

  // Deal feedback endpoints
  app.post('/api/deals/:dealId/feedback', async (req: any, res) => {
    try {
      const { dealId } = req.params;
      const feedbackData = req.body;

      const validatedData = insertDealFeedbackSchema.parse({
        ...feedbackData,
        dealId,
        userId: req.user?.id || null,
      });

      const feedback = await storage.createDealFeedback(validatedData);
      res.json(feedback);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return res.status(400).json({ message: "Invalid feedback data", errors: error.errors });
      }
      console.error("Error creating deal feedback:", error);
      res.status(500).json({ message: "Failed to submit feedback" });
    }
  });

  app.get('/api/deals/:dealId/feedback', async (req, res) => {
    try {
      const { dealId } = req.params;
      const feedback = await storage.getDealFeedback(dealId);
      res.json(feedback);
    } catch (error) {
      console.error("Error fetching deal feedback:", error);
      res.status(500).json({ message: "Failed to fetch feedback" });
    }
  });

  app.get('/api/deals/:dealId/feedback/stats', async (req, res) => {
    try {
      const { dealId } = req.params;
      const stats = await storage.getDealFeedbackStats(dealId);
      res.json(stats);
    } catch (error) {
      console.error("Error fetching feedback stats:", error);
      res.status(500).json({ message: "Failed to fetch feedback stats" });
    }
  });

  // Handle frequent HEAD /api requests efficiently (likely from monitoring)
  app.head('/api', (req, res) => {
    res.status(200).end();
  });

  // OAuth configuration status check
  app.get('/api/admin/oauth/status', async (req: any, res) => {
    // Only allow admins to check OAuth status
    if (!req.user || req.user.userType !== 'admin') {
      return res.status(403).json({ error: 'Admin access required' });
    }

    try {
      const baseUrl = process.env.PUBLIC_BASE_URL || 
                     (process.env.REPLIT_DOMAINS ? `https://${process.env.REPLIT_DOMAINS.split(',')[0]}` : 'http://localhost:5000');

      const status = {
        google: {
          configured: !!(process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET),
          clientIdPresent: !!process.env.GOOGLE_CLIENT_ID,
          clientSecretPresent: !!process.env.GOOGLE_CLIENT_SECRET,
          callbackUrls: {
            customer: `${baseUrl}/api/auth/google/customer/callback`,
            restaurant: `${baseUrl}/api/auth/google/restaurant/callback`,
          },
        },
        facebook: {
          configured: !!(process.env.FACEBOOK_APP_ID && process.env.FACEBOOK_APP_SECRET),
          appIdPresent: !!process.env.FACEBOOK_APP_ID,
          appSecretPresent: !!process.env.FACEBOOK_APP_SECRET,
          callbackUrl: `${baseUrl}/api/auth/facebook/callback`,
        },
        requiredUrls: {
          privacyPolicy: `${baseUrl}/privacy-policy`,
          dataDeletion: `${baseUrl}/data-deletion`,
          termsOfService: `${baseUrl}/terms-of-service`,
        },
        baseUrl,
        environment: process.env.NODE_ENV || 'development',
      };

      res.json(status);
    } catch (error) {
      console.error('Error checking OAuth status:', error);
      res.status(500).json({ error: 'Failed to check OAuth status' });
    }
  });

  // Health check endpoint for monitoring
  app.get('/api/health', async (req, res) => {
    try {
      // Test database connectivity
      await storage.getUser('health-check');

      res.json({
        status: 'healthy',
        timestamp: new Date().toISOString(),
        uptime: process.uptime(),
        environment: process.env.NODE_ENV || 'development',
        version: '1.0.0'
      });
    } catch (error) {
      res.status(503).json({
        status: 'unhealthy',
        error: 'Database connection failed',
        timestamp: new Date().toISOString()
      });
    }
  });

  const httpServer = createServer(app);
  return httpServer;
}

